      // Hebrew single-letter proclitics) is unreliable — it can land on an unrelated word
      // (كتبت→تبت "Tibet"). Flag it so the UI shows the result as uncertain rather than
      // confidently wrong. Multi-letter prefix strips (ال, וה) stay trusted.
      const risky = cand !== bare && bare.endsWith(cand) && bare.length - cand.length === 1;
      return { matched: cand, list, risky };
